class Solution {
public:
    vector<int> shortestAlternatingPaths(int n, vector<vector<int>>& redEdges, vector<vector<int>>& blueEdges) {
        vector<vector<pair<int, int>>> graph(n);
        for (auto& edge : redEdges) {
            graph[edge[0]].push_back({edge[1], 0}); // 0 for red edge
        }
        for (auto& edge : blueEdges) {
            graph[edge[0]].push_back({edge[1], 1}); // 1 for blue edge
        }

        vector<int> answer(n, INT_MAX);
        answer[0] = 0;

        queue<pair<int, int>> q; // node, color of edge used to reach node
        q.push({0, -1}); // start with node 0, no color

        int distance = 0;
        unordered_set<pair<int, int>> visited;
        while (!q.empty()) {
            int size = q.size();
            for (int i = 0; i < size; ++i) {
                auto [node, prevColor] = q.front();
                q.pop();

                for (auto& [neighbor, color] : graph[node]) {
                    if (color != prevColor && !visited.count({neighbor, color})) {
                        visited.insert({neighbor, color});
                        q.push({neighbor, color});
                        answer[neighbor] = min(answer[neighbor], distance + 1);
                    }
                }
            }
            distance++;
        }

        for (int i = 0; i < n; ++i) {
            if (answer[i] == INT_MAX) {
                answer[i] = -1;
            }
        }

        return answer;
    }
};
